INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'overview', 'Overview > Facts: National Institute of Technology Durgapur is located at Mahatma Gandhi Avenue, A-Zone, Bardhaman, Durgapur, West Bengal 713209.');
