INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'hostels', 'Hostels > Summary: 14 halls total. Boys hostels: H1, H2, H3, H4, H5, H9, H11, H14. Girls hostels: H6, H7, H8, H10, H13. International: H6 (girls), H12 (boys).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'mess', 'Mess > Monday Breakfast: Puri + Matar Aloo');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'mess', 'Mess > Monday Non-Veg: Fish. Veg: Kadai Paneer');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'mess', 'Mess > Tuesday Breakfast: Uttapam, Sambhar');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'mess', 'Mess > Wednesday Breakfast: Poha + Bananas');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'mess', 'Mess > Wednesday Lunch: Matar Paneer / Radhabhallavi + Chicken Do Pyaza + Gulab Jamun + Cold Drink');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'mess', 'Mess > Thursday Breakfast: Bread Butter + Egg');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'mess', 'Mess > Notes: Full weekly menu available in mess menu PDF.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'fee_structure', 'Fee Structure > Hostel Fee: Rs 19,000 per semester');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'fee_structure', 'Fee Structure > Caution Deposit: Rs 5,000');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'fee_structure', 'Fee Structure > Source: Image OCR of fee receipt (hard to read, confirmed by ambassador)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'wifi', 'Wifi > Facts: Every hostel at NIT Durgapur has individual WiFi with individual password and username. Speed is 100 Mbps.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'attendance', 'Attendance > Below 75%: 1 grade point deduction');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'attendance', 'Attendance > Below 50%: 2 grade point deduction');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'attendance', 'Attendance > Below 25%: Fail');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'attendance', 'Attendance > Notes: NIT Durgapur uses a unique grade-point deduction system for attendance rather than a simple pass/fail threshold.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'fests', 'Fests > Arohan: Tech fest held in October');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'fests', 'Fests > Cultural Fest: Held in January');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'fests', 'Fests > Monthly Club Fests: Runit (January), Recrave (October), E-Summit (February), Verve (March)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'laundry', 'Laundry > Facts: No washing machines in hostels. Students do self wash. Dhobi service available at Rs 15 per cloth.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'elections', 'Elections > Gymkhana: President, Vice President, General Secretary, Sports Secretary, Cultural Secretary');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'sports', 'Sports > Available: Football, Cricket, Kabaddi, Badminton, Kho-Kho, Yoga, Basketball, Running, Athletics, Chess, Handball');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'canteen', 'Canteen > On Campus: Chandu Cafe, Wonder Cafe, Spice Delight, DFC, Cafeteria, Nescafe, Techno');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'fines', 'Fines > Late Fee Payment: Rs 20/day for first 15 days, Rs 50/day after 15 days');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'gym', 'Gym > Girls Hostel Gym: One gym located in girls hostel, restricted to girls only');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'gym', 'Gym > Common Gym: Second gym available for both boys and girls');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'medical', 'Medical > Facility: 24x7 medical facility with guidance available');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Durgapur', 'medical', 'Medical > Insurance: Insurance card provided. Rs 90,000 insurance policy. Rs 10,000 OPD coverage.');
